def get_smallest_string(s: str) -> str:
    n = len(s)
    s_list = list(s)

    # Find the first non-'a' character to start the operation
    start = 0
    while start < n and s_list[start] == 'a':
        start += 1

    # If all characters are 'a', we must change the last character to 'z'
    if start == n:
        s_list[-1] = 'z'
        return ''.join(s_list)

    # Apply operation from start until we hit an 'a' or end of string
    end = start
    while end < n and s_list[end] != 'a':
        s_list[end] = chr(ord(s_list[end]) - 1)
        end += 1

    return ''.join(s_list)
